## ----setup, include=FALSE-----------------------------------------------------
knitr::opts_chunk$set(echo = FALSE, warning = FALSE, message = FALSE)
library(knitr)
library(kableExtra)
library(ggplot2)


## ----metric, fig.width = ifelse(knitr::is_html_output(), 8, 5.5), fig.height = 5, fig.cap = "Information criteria/metrics supported by 14 stepwise regression tools for each regression family", fig.alt="Information criteria/metrics supported by 14 stepwise regression tools for each regression family"----

platforms <- list(
  R = c("StepReg", "step()/stepAIC()", "leaps", "olsrr/blorr", "bestglm", "My.stepwise"),
  SAS = c("GLMSELECT", "LOGISTIC", "PHREG", "HPGENSELECT"),
  Python = c("stepwise-regression", "openturns")
)

types <- c("cox", "gamma", "linear", "logistic", "negbin", "poisson")
metrics <- c("adjRsq", "AIC", "AICc", "BIC", "Cp", "HQ", "IC(1)", "IC(3/2)", "SBC", "SL")

# Create the full dataframe skeleton
dat_list <- lapply(names(platforms), function(p) {
  expand.grid(Platform = p, Tools = platforms[[p]], Type = types, Metric = metrics)
})
dat <- do.call(rbind, dat_list)

# Initialize all as "Not supported"
dat$Support <- "Not supported"

dat$Support[dat$Tools == "StepReg" & dat$Type == "linear"] <- "Supported"
dat$Support[dat$Tools == "StepReg" & dat$Type != "linear" & !dat$Metric %in% c("Cp","BIC","adjRsq")] <- "Supported"
dat$Support[dat$Tools == "openturns" & dat$Type == "linear" & dat$Metric %in% c("AIC","SBC")] <- "Supported"
dat$Support[dat$Tools == "openturns" & dat$Type == "linear" & dat$Metric %in% c("IC(3/2)","IC(1)","HQ")] <- "Extended"
dat$Support[dat$Tools == "stepwise-regression" & dat$Type == "linear" & dat$Metric %in% c("SL")] <- "Supported"
dat$Support[dat$Tools == "bestglm" & dat$Type != "negbin" & dat$Metric %in% c("AIC","SBC")] <- "Supported"
dat$Support[dat$Tools == "leaps" & dat$Type == "linear" & dat$Metric %in% c("Cp","adjRsq")] <- "Supported"
dat$Support[dat$Tools == "My.stepwise" & dat$Type != "negbin" & dat$Metric %in% c("SL")] <- "Supported"
dat$Support[dat$Tools == "olsrr/blorr" & dat$Type == "linear" & dat$Metric %in% c("AIC","adjRsq","BIC","SBC","SL")] <- "Supported"
dat$Support[dat$Tools == "olsrr/blorr" & dat$Type == "logistic" & dat$Metric %in% c("AIC","SL")] <- "Supported"
dat$Support[dat$Tools == "step()/stepAIC()" & dat$Metric %in% c("AIC","SBC")] <- "Supported"
dat$Support[dat$Tools == "step()/stepAIC()" & dat$Metric %in% c("IC(3/2)","IC(1)","HQ")] <- "Extended"

dat$Support[dat$Tools == "GLMSELECT" & dat$Type == "linear" & !dat$Metric %in% c("IC(3/2)","IC(1)","HQ")] <- "Supported"
dat$Support[dat$Tools == "HPGENSELECT" & !dat$Type %in% c("cox","linear") & dat$Metric %in% "SL"] <- "Supported"
dat$Support[dat$Tools == "LOGISTIC" & dat$Type %in% c("logistic") & dat$Metric %in% "SL"] <- "Supported"
dat$Support[dat$Tools == "PHREG" & dat$Type %in% c("cox") & dat$Metric %in% "SL"] <- "Supported"

dat$platfrom_tool <- paste(dat$Platform, dat$Tools, sep = ": ")
row1_tools <- c("R: StepReg", "R: step()/stepAIC()", "R: olsrr/blorr", "R: bestglm")
row2_tools <- c("R: My.stepwise", "R: leaps", "Python: openturns", "Python: stepwise-regression")
sas_tools <- unique(dat$platfrom_tool[dat$Platform == "SAS"])
custom_order <- c(row1_tools, row2_tools, sas_tools)

dat$platfrom_tool <- factor(dat$platfrom_tool, levels = custom_order)
dat$Metric <- as.factor(dat$Metric)

ggplot(dat, aes(x = .data$Type, y = .data$Metric, fill = .data$Support)) +
  geom_tile(width = 0.99, height = 0.95, color = "black") +
  facet_wrap(~ .data$platfrom_tool) + 
  scale_fill_manual(values = c("Supported" = "palegreen2", "Not supported" = "white", "Extended" = "gray80")) +
  labs(x = "Regression type", y = "Metrics", title = "") + 
  theme(strip.background = element_rect(colour = "black", fill = "gray80"),
        strip.text = element_text(size = 5),
        panel.background = element_rect(fill = "white"), 
        plot.background = element_rect(fill = "white"),
        axis.text.x = element_text(angle = 60, hjust = 0.3, vjust = 0.5, size = 6),
        axis.text.y = element_text(size = 6),
        axis.title.x = element_text(size = 8),
        axis.title.y = element_text(size = 8),
        legend.text = element_text(size = 5),
        legend.title = element_text(size = 6)) +
  labs(fill = "Support status")



