## ----an example, echo=TRUE, eval=TRUE-----------------------------------------
library(StepReg)
data(lung)
lung$sex <- factor(lung$sex, levels = c(1, 2), labels = c("male", "female"))
lung <- na.omit(lung)
str(lung)


## ----an example2, echo=TRUE, eval=TRUE----------------------------------------
result <- stepwise(formula = Surv(time, status) ~ .,
                   data = lung,
                   type = "cox",
                   strategy = "forward",
                   metric = c("AICc", "SL"),
                   sle = 0.05,
                   test_ratio = 0.3)
result


## ----an example further explore, echo=TRUE, eval=TRUE-------------------------
coef(result$forward$SL)
result$forward$AICc$coefficients


## ----performance, echo=TRUE, eval=TRUE----------------------------------------
performance(x=result)


## ----visulization, out.width = "100%", out.height = "45%", fig.cap = "Visualization of variable selection: detailed and overview perspectives", fig.alt="Visualization of variable selection: detailed and overview perspectives", echo=TRUE, eval=TRUE----
library(cowplot)
plot_list <- setNames(
    lapply(c("forward"), function(i){
    setNames(
      lapply(c("detail", "overview"), function(j){
        plot(result, strategy=i, process=j)
      }),
        c("detail", "overview")
    )
    }),
    c("forward")
)
cowplot::plot_grid(plotlist = plot_list$forward, ncol = 1, rel_heights = c(2, 1))


